const EXPECTED_TOKEN = $input.first().json.CHAT_TOKEN;

const body = $input.first().json.body;

// Validate token
if (body.token !== EXPECTED_TOKEN) {
  throw new Error('Invalid webhook token');
}

// Strip trigger word and clean whitespace
const rawText = body.text || '';
const cleanText = rawText.replace(/@your-oncall-bot/gi, '').trim();

// Reject empty messages WITHOUT attachments.
// If file_ids is present we still want to process the message even if text is empty.
const rawFileIds = body.file_ids;
const hasAttachments = rawFileIds !== undefined
  && rawFileIds !== null
  && (Array.isArray(rawFileIds) ? rawFileIds.length > 0 : String(rawFileIds).trim() !== '');

if (!cleanText && !hasAttachments) {
  throw new Error('Empty message after removing trigger word');
}

// Normalize file_ids to an array of strings.
// Possible incoming shapes:
//   - undefined / null            → []
//   - "id1"                       → ["id1"]
//   - "id1,id2"                   → ["id1", "id2"]   (defensive, just in case)
//   - ["id1", "id2"]              → ["id1", "id2"]
function normalizeFileIds(value) {
  if (value === undefined || value === null) return [];
  if (Array.isArray(value)) {
    return value.map(v => String(v).trim()).filter(Boolean);
  }
  return String(value)
    .split(',')
    .map(v => v.trim())
    .filter(Boolean);
}

const fileIds = normalizeFileIds(rawFileIds);

// NOTE: we intentionally do NOT compute thread membership here.
// Mattermost outgoing webhook payload is not reliable for this —
// the AI Agent will resolve it via Mattermost MCP (get_thread).
return [{
  json: {
    message: cleanText,
    post_id: body.post_id,
    channel_id: body.channel_id,
    channel_name: body.channel_name,
    user_name: body.user_name,
    user_id: body.user_id,
    team_domain: body.team_domain,
    timestamp: body.timestamp,
    file_ids: fileIds,
    has_attachments: fileIds.length > 0
  }
}];

// Parse LLM classification response, validate category, fallback to "other"

const VALID_CATEGORIES = [
  'modify_infrastructure',
  'incident',
  'question',
  'ci_cd_error',
  'new_system',
  'announcement',
  'other'
];

const aiOutput = $input.first().json.text || $input.first().json.output || '';

// Robust JSON extraction — handles:
//   1) pure JSON
//   2) JSON wrapped in ```json ... ``` fences
//   3) JSON with prose before/after (agent "thinking out loud")
function extractJson(text) {
  if (!text) return null;

  // Prefer a fenced ```json ... ``` block if present
  const fenced = text.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (fenced && fenced[1]) {
    try { return JSON.parse(fenced[1].trim()); } catch (_) { /* fall through */ }
  }

  // Otherwise grab the widest {...} span and try to parse it
  const firstBrace = text.indexOf('{');
  const lastBrace = text.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace > firstBrace) {
    const candidate = text.slice(firstBrace, lastBrace + 1);
    try { return JSON.parse(candidate); } catch (_) { /* ignore */ }
  }

  // Last resort: raw parse
  try { return JSON.parse(text.trim()); } catch (_) { return null; }
}

let parsed = extractJson(aiOutput);
let parseFailed = false;

if (!parsed || typeof parsed !== 'object') {
  parseFailed = true;
  parsed = {
    category: 'other',
    confidence: 0,
    summary: 'Failed to parse AI response',
    acknowledge: '',
    is_thread: false,
    parent_post: ''
  };
}

if (!VALID_CATEGORIES.includes(parsed.category)) {
  parsed.category = 'other';
  parsed.confidence = 0;
}

// Pull upstream data (raw webhook extract)
const upstream = $('ValidateAndExtractMessage').first().json;

// Safety fallback: if the agent did not return parent_post, reply as a new
// thread rooted at the current post_id.
const parentPost = (parsed.parent_post && String(parsed.parent_post).trim())
  || upstream.post_id;

const isThread = parsed.is_thread === true;

return [{
  json: {
    ...upstream,
    category: parsed.category,
    confidence: parsed.confidence,
    summary: parsed.summary || '',
    acknowledge: parsed.acknowledge || '',
    is_thread: isThread,
    parent_post: parentPost,
    // Keep the old field name so downstream sub-workflows and reply nodes
    // that still reference `thread_root_id` continue to work unchanged.
    thread_root_id: parentPost,
    // Debug flag — useful when checking executions
    _parse_failed: parseFailed
  }
}];

const calendarEvents = $input.all();
const classification = $('Parse AI Response').first().json;

let onCallUser = 'unknown';

for (const event of calendarEvents) {
  const summary = event.json.summary || '';
  const match = summary.match(/@(\S+)/);
  if (match) {
    onCallUser = match[1]; // Mattermost @handle from calendar event title
    break;
  }
}

return [{
  json: {
    ...classification,
    on_call_user: onCallUser
  }
}];

